#include <stdio.h>
#include <stdlib.h>
#include <limits.h>
#include <inttypes.h>

int cmp_ll(const void *a, const void *b) {
    long long x = *(const long long *)a;
    long long y = *(const long long *)b;
    if (x < y) return -1;
    if (x > y) return 1;
    return 0;
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        long long *arr = (long long*)malloc(N * sizeof(long long));
        for (int i = 0; i < N; ++i) scanf("%lld", &arr[i]);
        qsort(arr, N, sizeof(long long), cmp_ll);
        long long cand[6];
        int cnt = 0;
        for (int i = 0; i < 3 && i < N; ++i) cand[cnt++] = arr[i];
        for (int i = N-3; i < N; ++i) if (i >= 0) cand[cnt++] = arr[i];
        long long best = LLONG_MIN;
        for (int i = 0; i < cnt; ++i) {
            for (int j = i+1; j < cnt; ++j) {
                long long a = cand[i], b = cand[j];
                long long val = a * b + llabs(a - b);
                if (val > best) best = val;
            }
        }
        printf("%lld\n", best);
        free(arr);
    }
    return 0;
}

