int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N; cin>>N;
        vector<long long> a(N);
        for(int i=0;i<N;++i) cin>>a[i];
        sort(a.begin(), a.end());
        vector<long long> cand;
        for(int i=0;i<3 && i<N;++i) cand.push_back(a[i]);
        for(int i=max(0,N-3); i<N; ++i) cand.push_back(a[i]);
        long long best = LLONG_MIN;
        for(size_t i=0;i<cand.size();++i){
            for(size_t j=i+1;j<cand.size();++j){
                long long x=cand[i], y=cand[j];
                long long val = x*y + llabs(x-y);
                best = max(best, val);
            }
        }
        cout<<best<<"\n";
    }
    return 0;
}

