import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            long[] arr = new long[N];
            for (int i = 0; i < N; i++) arr[i] = fs.nextLong();
            Arrays.sort(arr);
            List<Long> cand = new ArrayList<>();
            for (int i = 0; i < 3 && i < N; i++) cand.add(arr[i]);
            for (int i = Math.max(0, N - 3); i < N; i++) cand.add(arr[i]);
            long best = Long.MIN_VALUE;
            for (int i = 0; i < cand.size(); i++) {
                for (int j = i + 1; j < cand.size(); j++) {
                    long a = cand.get(i);
                    long b = cand.get(j);
                    long val = a * b + Math.abs(a - b);
                    if (val > best) best = val;
                }
            }
            sb.append(best).append('\n');
        }
        System.out.print(sb.toString());
    }

    // Fast scanner for large input
    static class FastScanner {
        private final BufferedInputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream stream) { in = new BufferedInputStream(stream); }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        long nextLong() throws IOException { int c; do { c = readByte(); } while (c <= ' ');
            boolean neg = false; if (c == '-') { neg = true; c = readByte(); }
            long val = 0; while (c > ' ') { val = val * 10 + (c - '0'); c = readByte(); }
            return neg ? -val : val; }
        int nextInt() throws IOException { return (int) nextLong(); }
    }
}

