const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
const T = input[idx++];
let outputs = [];
for (let t = 0; t < T; t++) {
  const N = input[idx++];
  const arr = input.slice(idx, idx + N);
  idx += N;
  arr.sort((a, b) => a - b);
  const cand = [];
  for (let i = 0; i < 3 && i < N; i++) cand.push(arr[i]);
  for (let i = Math.max(0, N - 3); i < N; i++) cand.push(arr[i]);
  let best = -Infinity;
  for (let i = 0; i < cand.length; i++) {
    for (let j = i + 1; j < cand.length; j++) {
      const a = cand[i];
      const b = cand[j];
      const val = a * b + Math.abs(a - b);
      if (val > best) best = val;
    }
  }
  outputs.push(String(best));
}
